{
  "grammar": [
    {
      "pattern": "那個 / 就是說 / 其實 + [sentence]",
      "structure": ["filler", "sentence"],
      "explanation_en": "Use fillers like 'nàge', 'jiùshì shuō', and 'qíshí' to sound more natural and less robotic in conversation. They give you thinking time and show hesitation or emphasis.",
      "title": "Natural Conversation Fillers",
      "meaning": "Using fillers to sound natural",
      "when_to_use": ["When you need a moment to think", "When you want to soften a statement", "When you want to emphasize a point"],
      "when_not_to_use": ["In formal writing or speeches", "When you need to be very direct"],
      "pragmatic_notes": "In Taiwan, '那個' is very common as a filler, similar to 'um' or 'well'. '就是說' means 'that is to say' and is used to rephrase. '其實' means 'actually' and adds a nuance of revealing truth.",
      "word_order_notes": "Fillers usually come at the beginning of a sentence or clause.",
      "english_contrast": "English uses 'um', 'well', 'actually' similarly, but Chinese fillers are more varied and context-specific.",
      "korean_contrast": "Korean uses '음', '그게', '사실은' similarly, but Chinese fillers are more integrated into sentence flow.",
      "negative_examples": [
        {
          "text": "那個我喜歡咖啡。",
          "error": "Missing comma or pause after filler; should be '那個，我喜歡咖啡。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "就是說我喜歡咖啡。",
          "error": "Using '就是說' without a preceding statement to rephrase; it should follow an idea."
        }
      ],
      "transformation_drills": ["Change '我喜歡咖啡' to include '那個' at the start.", "Add '其實' to '我不喜歡咖啡' to soften."],
      "production_drills": ["Say you like coffee but need a moment to think, using '那個'.", "Rephrase '我喜歡咖啡' using '就是說'."],
      "common_error_patterns": ["Overusing fillers", "Using fillers in formal contexts"],
      "repair_feedback": {
        "word_order": "Place filler at sentence start.",
        "politeness": "Fillers make speech softer and more polite.",
        "vocabulary": "Use '那個' for hesitation, '就是說' for rephrasing, '其實' for emphasis."
      }
    },
    {
      "pattern": "對啊 / 對不對 / 是不是 + [sentence]",
      "structure": ["filler", "sentence"],
      "explanation_en": "Use 'duì a', 'duì bù duì', and 'shì bù shì' to show agreement, seek confirmation, or engage the listener. These are common in Taiwanese conversation.",
      "title": "Agreement and Confirmation Fillers",
      "meaning": "Showing agreement or seeking confirmation",
      "when_to_use": ["When you agree with someone", "When you want to confirm understanding", "When you want to engage the listener"],
      "when_not_to_use": ["When you disagree", "In very formal settings"],
      "pragmatic_notes": "In Taiwan, '對啊' is a friendly way to agree. '對不對' and '是不是' are tag questions that invite the listener to respond, similar to 'right?' or 'isn't it?'.",
      "word_order_notes": "These fillers can come at the beginning or end of a sentence.",
      "english_contrast": "English uses 'right?', 'isn't it?', 'yeah' similarly, but Chinese tag questions are more frequent.",
      "korean_contrast": "Korean uses '그래', '맞지?', '그렇지?' similarly, but Chinese fillers are more varied.",
      "negative_examples": [
        {
          "text": "對啊我不喜歡咖啡。",
          "error": "Using '對啊' before a negative statement is contradictory; use '其實' instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "是不是我喜歡咖啡。",
          "error": "Using '是不是' as a filler without a tag question meaning; it should seek confirmation."
        }
      ],
      "transformation_drills": ["Change '我喜歡咖啡' to include '對啊' at the start.", "Add '對不對' to the end of '我喜歡咖啡'."],
      "production_drills": ["Agree that you like coffee using '對啊'.", "Ask if someone likes coffee using '是不是'."],
      "common_error_patterns": ["Using '對啊' with negative statements", "Overusing tag questions"],
      "repair_feedback": {
        "word_order": "Place '對啊' at start, '對不對' at end.",
        "politeness": "These fillers make conversation more interactive.",
        "vocabulary": "Use '對啊' for agreement, '對不對' for confirmation, '是不是' for tag questions."
      }
    },
    {
      "pattern": "就是 / 這樣子 / 然後 + [sentence]",
      "structure": ["filler", "sentence"],
      "explanation_en": "Use 'jiùshì', 'zhèyàng zi', and 'ránhòu' to connect ideas, summarize, or continue a story. They are common in natural Taiwanese speech.",
      "title": "Connecting and Summarizing Fillers",
      "meaning": "Connecting ideas or summarizing",
      "when_to_use": ["When you want to emphasize a point", "When you want to summarize", "When you want to continue a narrative"],
      "when_not_to_use": ["In very formal writing", "When you need to be concise"],
      "pragmatic_notes": "In Taiwan, '就是' is used to emphasize or clarify. '這樣子' means 'like this' and is used to summarize. '然後' means 'and then' and is used to continue a story.",
      "word_order_notes": "These fillers usually come at the beginning of a sentence or clause.",
      "english_contrast": "English uses 'like', 'so', 'and then' similarly, but Chinese fillers are more frequent in casual speech.",
      "korean_contrast": "Korean uses '그러니까', '이렇게', '그리고' similarly, but Chinese fillers are more varied.",
      "negative_examples": [
        {
          "text": "就是我喜歡咖啡。",
          "error": "Using '就是' without a preceding context; it should follow an idea to emphasize."
        }
      ],
      "incorrect_examples": [
        {
          "text": "這樣子我喜歡咖啡。",
          "error": "Using '這樣子' without a summary context; it should conclude a point."
        }
      ],
      "transformation_drills": ["Change '我喜歡咖啡' to include '就是' at the start.", "Add '然後' to connect '我喜歡咖啡' with '我也喜歡茶'."],
      "production_drills": ["Emphasize that you like coffee using '就是'.", "Summarize that you like coffee using '這樣子'."],
      "common_error_patterns": ["Overusing '然後' in every sentence", "Using '就是' without context"],
      "repair_feedback": {
        "word_order": "Place filler at sentence start.",
        "politeness": "These fillers make speech flow more naturally.",
        "vocabulary": "Use '就是' for emphasis, '這樣子' for summary, '然後' for continuation."
      }
    }
  ]
}
